import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"SKAdNetwork Dashboard Reports","description":"","frontmatter":{"title":"SKAdNetwork Dashboard Reports","slug":"skadnetwork-dashboard-reports"},"headers":[],"relativePath":"marketer-hub/skadnetwork-dashboard-reports.md","filePath":"marketer-hub/skadnetwork-dashboard-reports.md"}'),n={name:"marketer-hub/skadnetwork-dashboard-reports.md"};function i(s,e,d,l,h,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>This article is related to Branch’s legacy SKAdNetwork (SKAN) dashboard reporting experience.</p><p>Our new Branch Analysis tool offers customizable dashboards made up of flexible widgets to capture the data you need. Branch Analysis is being rolled out to customers in phases. While you&#39;re waiting for access, discover how to filter, share, and export campaign performance across different channels on our <a href="https://help.branch.io/docs/branch-analysis" target="_blank" rel="noreferrer">Analysis Overview</a> page.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>SKAdNetwork (SKAN), once enabled, will give you enhanced reporting on all of your SKAN-related campaigns directly on the Branch Dashboard.</p><h2 id="what-does-it-look-like" tabindex="-1">What does it look like? <a class="header-anchor" href="#what-does-it-look-like" aria-label="Permalink to &quot;What does it look like?&quot;">​</a></h2><p>The Branch Dashboard shows you all the information about your SKAN campaigns in the <strong>SKAdNetwork</strong> <a href="https://dashboard.branch.io/ads/analytics/skadnetwork" target="_blank" rel="noreferrer">tab</a>, which is found on the <strong>Analytics</strong> page under <strong>Ads</strong>.</p><p>.png &quot;SKAN Analytics.png&quot;)</p><p>You&#39;ll be able to determine:</p><ul><li><p>Which ad networks drove the most downloads</p></li><li><p>Which highest conversion events are being performed the most</p><ul><li>You can identify the effectiveness of each conversion value tier as <strong>low, medium, or high</strong> (only available for SKAN 4.0)</li></ul></li></ul><div class="info custom-block"><p class="custom-block-title">Branch SKAN Dashboard Availability</p><p>You are <em>only</em> able to view SKAN Data in the Branch in the following areas of the Branch Dashboard:</p><ul><li><strong>SKAN Activity</strong></li><li><strong>SKAN Unified View</strong></li></ul><p>You cannot view SKAN data in other areas of the Branch Dashboard (ex. <a href="https://dashboard.branch.io/sources" target="_blank" rel="noreferrer">Sources</a>) due to Apple&#39;s intentional SKAN design limitations: Apple only shares a <a href="https://developer.apple.com/documentation/storekit/skadnetwork/verifying_an_install_validation_postback#3592477" target="_blank" rel="noreferrer">limited amount of attribution data with advertisers</a> and does not provide any device-level data <em>(i.e., device ID, timestamps, geo, IP, etc.)</em> that could be used to deduplicate against other sources that Branch tracks.</p></div><h2 id="skan-unified-view" tabindex="-1">SKAN Unified View <a class="header-anchor" href="#skan-unified-view" aria-label="Permalink to &quot;SKAN Unified View&quot;">​</a></h2><p>There is also a view in the Branch Dashboard that combines both your SKAN and non-SKAN attribution data in one unified view called <strong>SKAN Unified View</strong>.</p><p>For more details, please see our full SKAN Unified View guide <a href="./unified-analytics.html">here</a>.</p><h2 id="skadnetwork-activity" tabindex="-1">SKAdNetwork Activity <a class="header-anchor" href="#skadnetwork-activity" aria-label="Permalink to &quot;SKAdNetwork Activity&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">SKAN 4.0+ Granularity</p><p>With SKAN 4.0+, additional attributed touch granularity will be available such as ad and creative. As ad networks expand their APIs to support these fields, Branch will retrieve all available data.</p></div><p>Different from how other Branch Dashboard reports are configurable, SKAN reports are configured mainly through setting a specific metric to compare. These metrics can be found at the top of the page underneath the <strong>Date Range</strong> section:</p><p>Selecting your preferred metric will dynamically update the report generated on this page.</p><table tabindex="0"><thead><tr><th>Compare By Metric</th><th>Description</th></tr></thead><tbody><tr><td>Ad Networks</td><td>Sets the <strong>Compare by</strong> parameters to: - date - ad network</td></tr><tr><td>Campaigns</td><td>Sets the <strong>Compare by</strong> parameters to: - date - ad network - campaign id</td></tr><tr><td>Source Apps</td><td>Sets the <strong>Compare by</strong> parameters to: - date - source app id</td></tr><tr><td>Conversion Events</td><td>Sets the <strong>Compare by</strong> parameters to: - date - conversion value</td></tr><tr><td>Downloads</td><td>Sets the <strong>Compare by</strong> parameters to: - date - download type</td></tr><tr><td>Custom Report</td><td>With <strong>Custom Report</strong>, you&#39;ll be able to create your own report using your chosen compare by parameters. This is helpful for things generating customized reports to show specific data. For example, <strong>Limit 2</strong> additional parameters.</td></tr></tbody></table><p>For more details on general Branch Dashboard Reports can be found <a href="./dashboard-reports.html">here</a>.</p><h4 id="dimensions" tabindex="-1">Dimensions <a class="header-anchor" href="#dimensions" aria-label="Permalink to &quot;Dimensions&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Dimension</th><th>Description</th></tr></thead><tbody><tr><td>Source App ID</td><td>This is the ID of the app that the ad was displayed in</td></tr><tr><td>Downloads</td><td>The total number of Postbacks that Branch receives for what you are filtering on.Downloads = Installs + Reinstalls</td></tr><tr><td>Installs</td><td>The total number of postbacks that Branch receives when redownload = <code>false</code> outside <a href="./skadnetwork-data.html#postback-data-tiers">second and third postback</a>. measurement window.</td></tr><tr><td>Reinstalls</td><td>The total number of postbacks that Branch receives when redownload = <code>true</code> outside <a href="./skadnetwork-data.html#postback-data-tiers">second and third postback</a> measurement window.</td></tr><tr><td>Total Conversion Events</td><td>The total number of postbacks with a conversion value (conversion value is not null).For example, if Branch receives ten postbacks with conversion value 5 and seven postbacks with conversion value 6, Total Conversion Events would equal 17.</td></tr><tr><td>Mapped Conversion Value</td><td>Description of what the conversion value is mapped to. In most cases, this will be an event name.</td></tr><tr><td>Coarse Conversion Value - Low, Medium, or High</td><td>Available only for SKAN 4.0. An indicator for for the coarse conversion value if the app provides one.</td></tr><tr><td>Coarse Conversion Value - UNAVAILABLE</td><td>Google Ads responds &#39;UNAVAILABLE&#39; for Crowd anonymity restrictions, if the postback contains a fine value, or v3 postbacks (coarse not supported)</td></tr><tr><td>Coarse Conversion Value - NONE</td><td>Advertiser coarse value configuration is missing for measurement window</td></tr><tr><td>Campaign ID</td><td>SKAdNetwork ID - Campaign ID from the Apple postback</td></tr><tr><td>Partner Campaign ID</td><td>Internal campaign ID from the ad partner. This is an optional field that ad partners can send to Branch and may not be available for all campaigns/ad partners.</td></tr><tr><td>Partner Campaign Name</td><td>Partner campaign name. This is an optional field that ad partners can send to Branch and may not be available for all campaigns/ad partners.</td></tr><tr><td>Download Type</td><td>Which type of download a row represents; this corresponds directly with the redownload value received in the postback. A &quot;false&quot; value indicates the data is for installs, and a &quot;true&quot; value indicates the data is for reinstalls.</td></tr><tr><td>Clicks</td><td>Number of times users tapped on the SKAN campaign.</td></tr><tr><td>Impressions</td><td>Number of times users saw the SKAN campaign.</td></tr><tr><td>Assists</td><td>The number of postbacks received by Apple that didn&#39;t win the final attribution but the user saw the ad. Up to five other ad networks can receive postbacks of non-winning attribution if their ad leads to an impression and is dependent on the ad partner providing that information to Branch.For example, if the user downloads the app from an ad click on Ad Network A, but saw the ad from Ad Networks, B, C, D, E, and F, the number of assists will be 5.</td></tr></tbody></table><h4 id="comparison-parameters" tabindex="-1">Comparison Parameters <a class="header-anchor" href="#comparison-parameters" aria-label="Permalink to &quot;Comparison Parameters&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td>Ad Network</td><td>The name of the ad network running the campaign.</td></tr><tr><td>Ad Set ID</td><td>Ad Set ID supplied by some ad partners.</td></tr><tr><td>Ad Set Name</td><td>Ad set name supplied by some ad partners.</td></tr><tr><td>Body Version</td><td>The version of the SKAdNetwork API being used by the publisher app.</td></tr><tr><td>Campaign ID</td><td>The Non-Apple Campaign ID supplied by some ad partners.</td></tr><tr><td>Conversion Value</td><td>Conversion value (0-63) which represents a post-install action. The highest conversion value that the end-user performed during the timer will be reflected.</td></tr><tr><td>Coarse Conversion Value - Low, Medium, or High</td><td>Available only for SKAN 4.0. An indicator for for the coarse conversion value if the app provides one.</td></tr><tr><td>Fidelity Type</td><td>If 1, this represents a Store-Kit rendered ad (App Store product page, rendered by Store Kit) If 0, this represents a &quot;View-Through&quot; ad (Custom, provided by ad network).</td></tr><tr><td>Mapped Alias</td><td>The annotated customer event alias.</td></tr><tr><td>Mapped Conversion Value</td><td>Mapped value of the conversion value received.</td></tr><tr><td>Mapped Lower Revenue</td><td>Mapped value of the lower revenue value received.</td></tr><tr><td>Mapped Upper Revenue</td><td>Mapped value of the upper revenue value received.</td></tr><tr><td>Partner Campaign ID</td><td>The ID of the SKAN campaign supplied by some ad partners.</td></tr><tr><td>Partner Campaign Name</td><td>The name of the SKAN campaign supplied by some ad partners.</td></tr><tr><td>Source App ID</td><td>App ID of publisher app.</td></tr></tbody></table><h3 id="skan-4" tabindex="-1">SKAN 4 <a class="header-anchor" href="#skan-4" aria-label="Permalink to &quot;SKAN 4&quot;">​</a></h3><p>SKAN 4 introduced new data fields that Branch can use to enhance your reporting to help you understand campaign performance. A simple way to look at SKAN 4-only metrics is to apply the following filter to the activity chart and/or table:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>body version</td><td>equals</td><td><code>4.0</code></td></tr></tbody></table><h4 id="coarse-conversion-value" tabindex="-1">Coarse Conversion Value <a class="header-anchor" href="#coarse-conversion-value" aria-label="Permalink to &quot;Coarse Conversion Value&quot;">​</a></h4><p>You can also generate reports to analyze your campaigns with respect to Tier 1+ postbacks for SKAN 4 campaigns. To do this, you can apply the following:</p><table tabindex="0"><thead><tr><th>Show</th><th>Compare by (Only for Custom Report)</th><th>Dimension</th></tr></thead><tbody><tr><td>- coarse conversion value - low - coarse conversion value - medium - coarse conversion value - high</td><td>- coarse conversion value</td><td>- coarse conversion value - low - coarse conversion value - medium - coarse conversion value - high</td></tr></tbody></table><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>SKAdNetwork (SKAN) introduced a brand new type of attribution when it comes to mobile measurement. As such, there can rise many different types of issues related to integration, data, and reporting. This guide serves to help debug and troubleshoot anything SKAN-related.</p><h4 id="data-is-not-appearing-in-the-branch-dashboard" tabindex="-1">Data is not Appearing in the Branch Dashboard <a class="header-anchor" href="#data-is-not-appearing-in-the-branch-dashboard" aria-label="Permalink to &quot;Data is not Appearing in the Branch Dashboard&quot;">​</a></h4><p>Because SKAdNetwork is meant to prevent the ability of any party to tie attributions back to a user, <strong>Apple only confirms conversions to advertisers after an undetermined threshold of conversions happens</strong> for the publisher &amp; campaign ID.</p><p><strong>SKAdNetwork does not attribute conversions in real time.</strong> When the app is installed, a 24-hour rolling timer begins, and only when that timer expires, can the install then be attributed after an additional 0-24 hours. Every time an additional conversion is reported with a conversion value greater than the previous value, the 24-hour rolling timer is reset and the install does not get attributed until that 24-hour timer is allowed to expire. <strong>Apple offers a developer profile</strong> <a href="https://developer.apple.com/download/more/" target="_blank" rel="noreferrer"><strong>here</strong></a><strong>, that can reduce the timers for testing from 24 hours to 5 minutes.</strong></p><div class="info custom-block"><p class="custom-block-title">App Clips</p><p>If your app uses <a href="https://developer.apple.com/app-clips/" target="_blank" rel="noreferrer">App Clips</a>, any API calls to SKAdNetwork from an app clip’s code will have no effect, return empty strings, or return values that indicate unavailability. See the disclaimer at the bottom of Apple&#39;s docs <a href="https://developer.apple.com/documentation/storekit/skadnetwork" target="_blank" rel="noreferrer">here</a>.</p></div><h4 id="fewer-conversions-after-updating-my-app-for-skadnetwork" tabindex="-1">Fewer conversions after updating my app for SKAdNetwork <a class="header-anchor" href="#fewer-conversions-after-updating-my-app-for-skadnetwork" aria-label="Permalink to &quot;Fewer conversions after updating my app for SKAdNetwork&quot;">​</a></h4><p>When a conversion is reported to Apple from inside the app, it does not add that count to a running tally or immediately sends a conversion postback. It only replaces the prior reported conversion value, as long as its value is a higher priority (63 is the highest priority, 0 is the lowest).</p><p>When the app is installed, a 24-hour rolling timer begins. If no additional conversion is reported before that 24-hour rolling timer expires, only an install will be attributed to that user. Any subsequent conversions sent to Apple for that user will not be attributed.</p><p>This means that for any user, Apple will at most, only report a single postback containing an Install or Reinstall and the highest priority conversion associated with that install session.</p><h4 id="i-m-not-seeing-my-event-metadata-in-the-branch-dashboard" tabindex="-1">I&#39;m not seeing my event metadata in the Branch Dashboard <a class="header-anchor" href="#i-m-not-seeing-my-event-metadata-in-the-branch-dashboard" aria-label="Permalink to &quot;I&#39;m not seeing my event metadata in the Branch Dashboard&quot;">​</a></h4><p>SKAdNetwork works differently from traditional app attribution systems, which means the data you see is more limited.</p><ul><li><strong>Traditional attribution</strong>. Typically, when you track events via the Branch SDK, you can view contextual metadata (i.e., Geo, Revenue, timestamp) for those events in the Branch dashboard.</li><li><strong>SKAdNetwork attribution</strong>. SKAdNetwork only allows a single conversion value for down-funnel reporting, and Apple intentionally designed the system to <a href="https://developer.apple.com/documentation/storekit/skadnetwork/verifying_an_install_validation_postback#3592477" target="_blank" rel="noreferrer">limit the contextual metadata available for that event</a>. This means you won&#39;t see event metadata like Geo, Revenue, or timestamp for SKAdNetwork events in the Branch dashboard.</li></ul><h4 id="skan-reinstall-numbers" tabindex="-1">SKAN Reinstall Numbers <a class="header-anchor" href="#skan-reinstall-numbers" aria-label="Permalink to &quot;SKAN Reinstall Numbers&quot;">​</a></h4><p>SKAdNetwork reports reinstalls via the <code>redownload</code> postback parameter, which Apple defines this way:</p><blockquote><p>A Boolean flag that indicates the customer redownloaded and reinstalled the app when the value is true.</p></blockquote><p>Similar to <a href="https://searchads.apple.com/help/advanced/0027-mobile-measurement-providers/" target="_blank" rel="noreferrer">the Redownload numbers provided by Apple Ads</a>, this data is likely coming directly from Apple&#39;s internal records for that customer. That means it is different from (and more accurate than) anything a third-party like Branch could infer, even prior to iOS 14: depending on the situation, Branch would see these events as either re-opens or simple installs.</p>',45)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
